{
  "schema": "brainflow.cli_arg_length_policy.v1",
  "windows": {
    "max_cmd_chars": 6000,
    "prefer_file_args": true,
    "argfile_extensions": [".json", ".yaml", ".txt"],
    "notes": "Use @argfile or file-path inputs for large prompts/payloads to avoid Win32 command line limits."
  }
}
